<script setup lang="ts">import{computed,ref}from'vue';import{useGrantStore}from'../store';import MediaCard from'../components/MediaCard.vue';const store=useGrantStore(),search=ref(''),domain=ref('All'),domains=computed(()=>['All',...new Set(store.programmes.map(x=>x.domain))]),filtered=computed(()=>store.programmes.filter(x=>(domain.value==='All'||x.domain===domain.value)&&`${x.title} ${x.provider}`.toLowerCase().includes(search.value.toLowerCase())))</script><template><main><section class="hero"><div><span>European funding intelligence</span><h1>Find the right call. Build the stronger bid.</h1><p>Match strategic programmes to organisational capability and deadlines.</p><button @click="store.toggleSaved(1)">Shortlist recommended call</button><button class="ghost">Review portfolio</button></div></section><section class="controls"><div><h2>Funding radar</h2><p>Current programmes matched to your delivery profile.</p></div><input v-model="search" aria-label="Search funding calls" placeholder="Search calls or programmes"/><select v-model="domain" aria-label="Filter by domain"><option v-for="item in domains" :key="item">{{item}}</option></select></section><TransitionGroup v-if="filtered.length" name="list" tag="section" class="media-grid"><MediaCard v-for="item in filtered" :key="item.id" :programme="item"/></TransitionGroup><div v-else class="empty">No funding calls match this search.</div></main></template>
